VALUES
  ('diplomatic-535efab1-moex-00016', 'diplomatic-535efab1', 'diplomatic-535efab1-moex-114-10317cea', 'sub-diplomatic-535efab1-02', NULL, 'single_choice', 'Pactatertiisnecnocentnecprosunt一詞之意義為何？', '["條約神聖原則", "需經國家同意方能使條約生效", "條約僅對締約國生效，不對第三國產生義務", "情勢發生重大且不可預見之變化"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:33+00:00", "source_pdf_sha1": "50baf7169a04", "answer_pdf_sha1": "f8981815935e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際公法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-英文組"}'::jsonb, NULL),
  ('diplomatic-535efab1-moex-00017', 'diplomatic-535efab1', 'diplomatic-535efab1-moex-114-10317cea', 'sub-diplomatic-535efab1-02', NULL, 'single_choice', '關於「不干涉內政原則」，下列敘述何者錯誤？', '["國際法基本規則要求，一國沒有權利侵害其他國家對國內事務的管轄", "依《聯合國憲章》第7章所為的執行措施，得適用於一國國內管轄事件", "依《聯合國憲章》規定，聯合國原則上不得干涉一國國內管轄事件", "依《聯合國憲章》要求，會員國須將所有爭端依憲章提交國際法院解決"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:33+00:00", "source_pdf_sha1": "50baf7169a04", "answer_pdf_sha1": "f8981815935e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際公法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-英文組"}'::jsonb, NULL),
  ('diplomatic-535efab1-moex-00018', 'diplomatic-535efab1', 'diplomatic-535efab1-moex-114-10317cea', 'sub-diplomatic-535efab1-02', NULL, 'single_choice', '關於國際法上的「國家繼承」，下列敘述何者錯誤？', '["1978年《關於國家在條約方面的繼承的維也納公約》，與《維也納外交關係公約》相比，前者 之爭議性較大", "1978年《關於國家在條約方面的繼承的維也納公約》為國家繼承原則之法典化成果之一", "國際法委員會於1983年已通過《關於國家在財產、檔案及債務方面的繼承的維也納公約》，但 該公約尚未生效", "國家繼承包括因交戰關係而占領等暫時性的改變"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:33+00:00", "source_pdf_sha1": "50baf7169a04", "answer_pdf_sha1": "f8981815935e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際公法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-英文組"}'::jsonb, NULL),
  ('diplomatic-535efab1-moex-00019', 'diplomatic-535efab1', 'diplomatic-535efab1-moex-114-10317cea', 'sub-diplomatic-535efab1-02', NULL, 'single_choice', '關於「人權」，下列敘述何者正確？', '["《經濟社會文化權利國際公約》並沒有提到民族（人民）自決權", "《聯合國憲章》第1條規定，聯合國設立的目的是在達成國際合作，藉以促進和鼓勵對全體人 類之人權與基本自由的尊重", "《國際人權憲章》是《公民與政治權利國際公約》及《經濟社會文化權利國際公約》二者之總稱", "人權事務屬於一國的國內管轄範圍，不適用國際法規範"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:33+00:00", "source_pdf_sha1": "50baf7169a04", "answer_pdf_sha1": "f8981815935e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際公法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-英文組"}'::jsonb, NULL),
  ('diplomatic-535efab1-moex-00020', 'diplomatic-535efab1', 'diplomatic-535efab1-moex-114-10317cea', 'sub-diplomatic-535efab1-02', NULL, 'single_choice', '下列區域何者並未受多邊公約之規範？', '["國家管轄以外的海床和洋底及其底土", "南極", "地心", "蘇伊士運河"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:33+00:00", "source_pdf_sha1": "50baf7169a04", "answer_pdf_sha1": "f8981815935e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際公法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-英文組"}'::jsonb, NULL),
  ('diplomatic-535efab1-moex-00021', 'diplomatic-535efab1', 'diplomatic-535efab1-moex-114-10317cea', 'sub-diplomatic-535efab1-02', NULL, 'single_choice', '依據《聯合國海洋法公約》第39條，關於船舶與航空器「過境通行」之義務，下列敘述何者錯誤？', '["船舶與航空器應毫不遲延地通過或飛越海峽", "船舶與航空器不得對海峽沿岸國的主權、領土完整或政治獨立進行任何武力威脅或使用武力", "船舶與航空器除因不可抗力或遇難而有必要外，不得從事其繼續不停和迅速過境的通常方式所 附帶發生的活動以外的任何活動", "船舶與航空器得進行任何研究或測量活動"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:33+00:00", "source_pdf_sha1": "50baf7169a04", "answer_pdf_sha1": "f8981815935e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際公法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-英文組"}'::jsonb, NULL),
  ('diplomatic-535efab1-moex-00022', 'diplomatic-535efab1', 'diplomatic-535efab1-moex-114-10317cea', 'sub-diplomatic-535efab1-02', NULL, 'single_choice', '依據《聯合國海洋法公約》，關於群島水域，下列敘述何者錯誤？', '["群島國應尊重其他國家所鋪設的通過其水域而不靠岸的現有海底電纜", "群島國應承認直接相鄰國在群島水域範圍內某些區域的傳統捕魚權", "原則上所有國家的船舶均享有通過群島水域的無害通過權", "航空器不享有群島水域空中通行權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:33+00:00", "source_pdf_sha1": "50baf7169a04", "answer_pdf_sha1": "f8981815935e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際公法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-英文組"}'::jsonb, NULL),
  ('diplomatic-535efab1-moex-00023', 'diplomatic-535efab1', 'diplomatic-535efab1-moex-114-10317cea', 'sub-diplomatic-535efab1-02', NULL, 'single_choice', '有關世界貿易組織之爭端解決機構，下列敘述何者正確？', '["世界貿易組織爭端解決機構是國際貿易法領域中成立的第一個爭端解決機制", "《世界貿易組織協定》係爭端解決機構適用之唯一法源", "爭端解決機構就《世界貿易組織協定》之爭端，享有強制和專屬的管轄權", "爭端解決機構已獲得世界貿易組織會員之信任，向其上訴機構提出上訴的比率相當低"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:33+00:00", "source_pdf_sha1": "50baf7169a04", "answer_pdf_sha1": "f8981815935e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際公法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-英文組"}'::jsonb, NULL),
  ('diplomatic-535efab1-moex-00024', 'diplomatic-535efab1', 'diplomatic-535efab1-moex-114-10317cea', 'sub-diplomatic-535efab1-02', NULL, 'single_choice', '下列何者並非一國法院經常用以決定跨境電信詐騙犯罪案件管轄權之依據？', '["領域管轄", "普遍管轄", "行為人國籍管轄", "被害者國籍管轄"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:33+00:00", "source_pdf_sha1": "50baf7169a04", "answer_pdf_sha1": "f8981815935e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際公法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-英文組"}'::jsonb, NULL),
  ('diplomatic-535efab1-moex-00025', 'diplomatic-535efab1', 'diplomatic-535efab1-moex-114-10317cea', 'sub-diplomatic-535efab1-02', NULL, 'single_choice', '依2001年《國家對國際不法行為的責任條款草案》，關於「一國國際不法行為之要素」，下列敘述 何者錯誤？', '["是由一個不法的作為或不作為造成", "存在一個違反義務的作為或不作為", "不法的作為或不作為是可歸責於某一個國家", "國際不法行為之認定應依國際法及國內法共同為之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:33+00:00", "source_pdf_sha1": "50baf7169a04", "answer_pdf_sha1": "f8981815935e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際公法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-英文組"}'::jsonb, NULL)
